final class KeychainService {
    static let shared = KeychainService()
    private init() {}

    func save(_ value: String, for key: String) {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }

    func read(_ key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess,
              let data = result as? Data,
              let value = String(data: data, encoding: .utf8) else { return nil }
        return value
    }

    func delete(_ key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

final class SecureAPIClient {
    static let shared = SecureAPIClient()

    private let session: URLSession
    private let baseURL: URL
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private let tokenKey = "trading_api_token"

    private init() {
        self.baseURL = URL(string: "https://api.yourbroker.com/v1")!
        let config = URLSessionConfiguration.default
        config.waitsForConnectivity = true
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        self.session = URLSession(configuration: config)
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
        self.decoder.dateDecodingStrategy = .iso8601
        self.encoder.dateEncodingStrategy = .iso8601
    }

    func setAuthToken(_ token: String) {
        KeychainService.shared.save(token, for: tokenKey)
    }

    func clearAuthToken() {
        KeychainService.shared.delete(tokenKey)
    }

    private func makeRequest(path: String, method: String, body: Data? = nil) -> URLRequest {
        var request = URLRequest(url: baseURL.appendingPathComponent(path))
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        if let token = KeychainService.shared.read(tokenKey) {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        request.httpBody = body
        return request
    }

    private func perform<T: Decodable>(_ request: URLRequest) async throws -> T {
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse else {
            throw URLError(.badServerResponse)
        }
        guard (200...299).contains(http.statusCode) else {
            if let apiError = try? decoder.decode(APIErrorResponse.self, from: data) {
                throw NSError(domain: "TradingAPI", code: http.statusCode, userInfo: [NSLocalizedDescriptionKey: apiError.message])
            }
            throw NSError(domain: "TradingAPI", code: http.statusCode, userInfo: [NSLocalizedDescriptionKey: "Request failed"])
        }
        return try decoder.decode(T.self, from: data)
    }

    func fetchQuotes(symbols: [String]) async throws -> [StockQuote] {
        let joined = symbols.joined(separator: ",")
        let request = makeRequest(path: "quotes?symbols=\(joined)", method: "GET")
        return try await perform(request)
    }

    func fetchPortfolio() async throws -> (summary: PortfolioSummary, positions: [PortfolioPosition]) {
        struct PortfolioPayload: Codable {
            let summary: PortfolioSummary
            let positions: [PortfolioPosition]
        }
        let request = makeRequest(path: "portfolio", method: "GET")
        let payload: PortfolioPayload = try await perform(request)
        return (payload.summary, payload.positions)
    }

    func submitTrade(_ trade: TradeRequest) async throws -> TradeOrder {
        let body = try encoder.encode(trade)
        let request = makeRequest(path: "orders", method: "POST", body: body)
        let response: TradeResponse = try await perform(request)
        return response.order
    }

    func cancelOrder(orderID: String) async throws -> TradeOrder {
        let request = makeRequest(path: "orders/\(orderID)/cancel", method: "POST")
        let response: TradeResponse = try await perform(request)
        return response.order
    }

    func fetchOrders() async throws -> [TradeOrder] {
        let request = makeRequest(path: "orders", method: "GET")
        return try await perform(request)
    }
}

@MainActor
final class TradingViewModel: ObservableObject {
    @Published var quotes: [StockQuote] = []
    @Published var portfolioSummary = PortfolioSummary(cashBalance: 0, buyingPower: 0, dayChange: 0, dayChangePercent: 0, totalEquity: 0, totalMarketValue: 0, totalCostBasis: 0, totalUnrealizedPnL: 0)
    @Published var positions: [PortfolioPosition] = []
    @Published var orders: [TradeOrder] = []
    @Published var selectedSymbol: String = "AAPL"
    @Published var quantity: Int = 1
    @Published var limitPrice: String = ""
    @Published var orderType: OrderType = .market
    @Published var side: TradeSide = .buy
    @Published var isSubmitting = false
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var successMessage: String?

    private let api = SecureAPIClient.shared
    private var refreshTask: Task<Void, Never>?

    func configureAuth(token: String) {
        api.setAuthToken(token)
    }

    func startRealtimeUpdates() {
        refreshTask?.cancel()
        refreshTask = Task {
            while !Task.isCancelled {
                await refreshAll()
                try? await Task.sleep(nanoseconds: 5_000_000_000)
            }
        }
    }

    func stopRealtimeUpdates() {
        refreshTask?.cancel()
        refreshTask = nil
    }

    func refreshAll() async {
        isLoading = true
        defer { isLoading = false }
        do {
            async let quotesTask = api.fetchQuotes(symbols: [selectedSymbol, "SPY", "QQQ"])
            async let portfolioTask = api.fetchPortfolio()
            async let ordersTask = api.fetchOrders()

            let fetchedQuotes = try await quotesTask
            let portfolio = try await portfolioTask
            let fetchedOrders = try await ordersTask

            quotes = fetchedQuotes
            portfolioSummary = portfolio.summary
            positions = portfolio.positions
            orders = fetchedOrders.sorted { $0.updatedAt > $1.updatedAt }
            errorMessage = nil
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func submitTrade() async {
        guard quantity > 0 else {
            errorMessage = "Quantity must be greater than zero."
            return
        }
        if orderType == .limit {
            guard let price = Double(limitPrice), price > 0 else {
                errorMessage = "Enter a valid limit price."
                return
            }
        }

        isSubmitting = true
        defer { isSubmitting = false }

        do {
            let request = TradeRequest(
                symbol: selectedSymbol.uppercased(),
                side: side,
                orderType: orderType,
                quantity: quantity,
                limitPrice: orderType == .limit ? Double(limitPrice) : nil
            )
            let order = try await api.submitTrade(request)
            orders.insert(order, at: 0)
            successMessage = "\(side.rawValue.capitalized) order submitted for \(selectedSymbol.uppercased())."
            errorMessage = nil
            await refreshAll()
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func cancel(order: TradeOrder) async {
        do {
            let updated = try await api.cancelOrder(orderID: order.id)
            if let index = orders.firstIndex(where: { $0.id == updated.id }) {
                orders[index] = updated
            }
            successMessage = "Order cancelled."
            errorMessage = nil
            await refreshAll()
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func quote(for symbol: String) -> StockQuote? {
        quotes.first { $0.symbol.uppercased() == symbol.uppercased() }
    }

    func position(for symbol: String) -> PortfolioPosition? {
        positions.first { $0.symbol.uppercased() == symbol.uppercased() }
    }
}

